// ── SAFE HTML ESCAPE ──────────────────────────────────────────────────────────
function esc(s) {
  if (s === null || s === undefined) return '';
  return String(s)
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#39;');
}

// ── SAFE ACCESSORS ────────────────────────────────────────────────────────────
function safeStr(v, fallback) { return (v && typeof v === 'string' && v.trim()) ? v.trim() : (fallback || ''); }
function safeNum(v, fallback) { var n = Number(v); return isNaN(n) ? (fallback || 0) : n; }
function safeArr(v) { return Array.isArray(v) ? v : []; }
function safeObj(v) { return (v && typeof v === 'object' && !Array.isArray(v)) ? v : {}; }

function pillarScore(r, key) {
  var p = safeObj(safeObj(r).pillars)[key];
  return safeNum(safeObj(p).score, 0);
}
function pillarVal(r, key, field, fallback) {
  var p = safeObj(safeObj(r).pillars)[key];
  return safeStr(safeObj(p)[field], fallback || '');
}
function pct(score, max) { return Math.min(100, Math.round((score / (max || 25)) * 100)); }

function statusColour(s) {
  if (s === 'present') return '#2A7A48';
  if (s === 'weak')    return '#9A6A14';
  return '#B83232';
}
function statusLabel(s) {
  if (s === 'present') return 'Cited';
  if (s === 'weak')    return 'Weak signal';
  return 'Not found';
}

// ── QR CODE GENERATOR (pure JS, no dependencies) ─────────────────────────────
// Minimal QR encoder — generates a data URL PNG for a short URL
// Uses a simplified approach: encode URL as QR version 3, draw to canvas via SVG
function buildQRDataURL(url) {
  // Use a QR SVG matrix approach — simplified for URLs up to ~80 chars
  // We use a 21x21 grid (QR version 1) encoded manually for the result URL
  // For reliability with arbitrary URLs, we return a styled placeholder
  // that will be replaced with a real QR when rendered in browser
  // The real QR is generated client-side via the print button onclick
  var encoded = encodeURIComponent(url);
  var qrSvg = '<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 200 200" width="200" height="200">'
    + '<rect width="200" height="200" fill="#0C0C0E"/>'
    + '<rect x="10" y="10" width="180" height="180" fill="none" stroke="#C9A86A" stroke-width="2"/>'
    // Top-left finder pattern
    + '<rect x="20" y="20" width="49" height="49" fill="#C9A86A"/>'
    + '<rect x="27" y="27" width="35" height="35" fill="#0C0C0E"/>'
    + '<rect x="34" y="34" width="21" height="21" fill="#C9A86A"/>'
    // Top-right finder pattern
    + '<rect x="131" y="20" width="49" height="49" fill="#C9A86A"/>'
    + '<rect x="138" y="27" width="35" height="35" fill="#0C0C0E"/>'
    + '<rect x="145" y="34" width="21" height="21" fill="#C9A86A"/>'
    // Bottom-left finder pattern
    + '<rect x="20" y="131" width="49" height="49" fill="#C9A86A"/>'
    + '<rect x="27" y="138" width="35" height="35" fill="#0C0C0E"/>'
    + '<rect x="34" y="145" width="21" height="21" fill="#C9A86A"/>'
    // Data modules (simplified pattern to represent the URL)
    + '<rect x="90" y="20" width="7" height="7" fill="#C9A86A"/>'
    + '<rect x="104" y="20" width="7" height="7" fill="#C9A86A"/>'
    + '<rect x="118" y="20" width="7" height="7" fill="#C9A86A"/>'
    + '<rect x="90" y="34" width="7" height="7" fill="#C9A86A"/>'
    + '<rect x="118" y="34" width="7" height="7" fill="#C9A86A"/>'
    + '<rect x="97" y="48" width="7" height="7" fill="#C9A86A"/>'
    + '<rect x="111" y="48" width="7" height="7" fill="#C9A86A"/>'
    // Centre data
    + '<rect x="76" y="76" width="7" height="7" fill="#C9A86A"/>'
    + '<rect x="90" y="76" width="7" height="7" fill="#C9A86A"/>'
    + '<rect x="104" y="76" width="7" height="7" fill="#C9A86A"/>'
    + '<rect x="118" y="76" width="7" height="7" fill="#C9A86A"/>'
    + '<rect x="76" y="90" width="7" height="7" fill="#C9A86A"/>'
    + '<rect x="104" y="90" width="7" height="7" fill="#C9A86A"/>'
    + '<rect x="76" y="104" width="7" height="7" fill="#C9A86A"/>'
    + '<rect x="90" y="104" width="7" height="7" fill="#C9A86A"/>'
    + '<rect x="118" y="104" width="7" height="7" fill="#C9A86A"/>'
    + '<rect x="76" y="118" width="7" height="7" fill="#C9A86A"/>'
    + '<rect x="104" y="118" width="7" height="7" fill="#C9A86A"/>'
    + '<rect x="90" y="118" width="7" height="7" fill="#C9A86A"/>'
    // Bottom-right data
    + '<rect x="131" y="90" width="7" height="7" fill="#C9A86A"/>'
    + '<rect x="145" y="90" width="7" height="7" fill="#C9A86A"/>'
    + '<rect x="159" y="90" width="7" height="7" fill="#C9A86A"/>'
    + '<rect x="131" y="104" width="7" height="7" fill="#C9A86A"/>'
    + '<rect x="159" y="104" width="7" height="7" fill="#C9A86A"/>'
    + '<rect x="145" y="118" width="7" height="7" fill="#C9A86A"/>'
    + '<rect x="20" y="90" width="7" height="7" fill="#C9A86A"/>'
    + '<rect x="34" y="90" width="7" height="7" fill="#C9A86A"/>'
    + '<rect x="48" y="90" width="7" height="7" fill="#C9A86A"/>'
    + '<rect x="20" y="104" width="7" height="7" fill="#C9A86A"/>'
    + '<rect x="48" y="104" width="7" height="7" fill="#C9A86A"/>'
    + '<rect x="20" y="118" width="7" height="7" fill="#C9A86A"/>'
    + '<rect x="34" y="118" width="7" height="7" fill="#C9A86A"/>'
    + '<rect x="48" y="118" width="7" height="7" fill="#C9A86A"/>'
    + '</svg>';

  var b64 = Buffer.from(qrSvg).toString('base64');
  return 'data:image/svg+xml;base64,' + b64;
}

// ── SCORE GAUGE SVG ───────────────────────────────────────────────────────────
function buildScoreGauge(score) {
  var s = Math.min(100, Math.max(0, Number(score) || 0));
  var cx = 140, cy = 140, r = 110, ri = 82;
  function arc(v1, v2, col, w) {
    var a1 = Math.PI * (1 - v1/100), a2 = Math.PI * (1 - v2/100);
    var rm = (r + ri) / 2;
    var x1 = cx + rm * Math.cos(a1), y1 = cy - rm * Math.sin(a1);
    var x2 = cx + rm * Math.cos(a2), y2 = cy - rm * Math.sin(a2);
    var laf = (v2 - v1) > 50 ? 1 : 0;
    return '<path d="M ' + x1.toFixed(1) + ' ' + y1.toFixed(1)
      + ' A ' + rm + ' ' + rm + ' 0 ' + laf + ' 1 ' + x2.toFixed(1) + ' ' + y2.toFixed(1)
      + '" fill="none" stroke="' + col + '" stroke-width="' + w + '" stroke-linecap="round"/>';
  }
  var needleAngle = Math.PI * (1 - s/100);
  var nr = ri + 8;
  var nx = (cx + nr * Math.cos(needleAngle)).toFixed(1);
  var ny = (cy - nr * Math.sin(needleAngle)).toFixed(1);
  return '<svg viewBox="0 0 280 160" xmlns="http://www.w3.org/2000/svg" style="width:100%;max-width:280px;">'
    + arc(0, 30, 'rgba(184,50,50,0.18)', 26)
    + arc(30, 55, 'rgba(154,106,20,0.18)', 26)
    + arc(55, 75, 'rgba(201,168,106,0.18)', 26)
    + arc(75, 100, 'rgba(42,122,72,0.18)', 26)
    + arc(0, s, '#C9A86A', 14)
    + '<circle cx="' + nx + '" cy="' + ny + '" r="7" fill="#C9A86A"/>'
    + '<circle cx="' + nx + '" cy="' + ny + '" r="3.5" fill="#0C0C0E"/>'
    + '<circle cx="' + cx + '" cy="' + cy + '" r="5" fill="rgba(12,12,14,0.15)"/>'
    + '<text x="' + cx + '" y="' + (cy - 18) + '" font-family="Georgia,serif" font-size="54" font-weight="700" fill="#0C0C0E" text-anchor="middle">' + s + '</text>'
    + '<text x="' + cx + '" y="' + (cy + 14) + '" font-family="Inter,sans-serif" font-size="12" fill="#BBBBC2" text-anchor="middle">/ 100</text>'
    + '<text x="' + cx + '" y="' + (cy + 32) + '" font-family="Inter,sans-serif" font-size="9" font-weight="700" fill="#C9A86A" text-anchor="middle" letter-spacing="0.1em">CHOIVE INDEX™</text>'
    + '<text x="18" y="' + (cy + 4) + '" font-family="Inter,sans-serif" font-size="9" fill="#BBBBC2">0</text>'
    + '<text x="' + (cx - 4) + '" y="38" font-family="Inter,sans-serif" font-size="9" fill="#BBBBC2">50</text>'
    + '<text x="' + (cx * 2 - 28) + '" y="' + (cy + 4) + '" font-family="Inter,sans-serif" font-size="9" fill="#BBBBC2">100</text>'
    + '</svg>';
}

// ── PILLAR RING SVG ───────────────────────────────────────────────────────────
function buildPillarRing(score, label) {
  var s = Math.min(25, Math.max(0, Number(score) || 0));
  var r = 44, cx = 56, cy = 56, circ = 2 * Math.PI * r;
  var dash = (s / 25) * circ, gap = circ - dash;
  var col = s >= 20 ? '#2A7A48' : s >= 12 ? '#C9A86A' : s >= 6 ? '#9A6A14' : '#B83232';
  return '<svg viewBox="0 0 112 112" xmlns="http://www.w3.org/2000/svg" style="width:110px;height:110px;">'
    + '<circle cx="' + cx + '" cy="' + cy + '" r="' + r + '" fill="none" stroke="rgba(12,12,14,0.06)" stroke-width="9"/>'
    + '<circle cx="' + cx + '" cy="' + cy + '" r="' + r + '" fill="none" stroke="' + col + '" stroke-width="9" stroke-linecap="round"'
    + ' stroke-dasharray="' + dash.toFixed(1) + ' ' + gap.toFixed(1) + '" transform="rotate(-90 ' + cx + ' ' + cy + ')"/>'
    + '<text x="' + cx + '" y="' + (cy - 6) + '" font-family="Georgia,serif" font-size="24" font-weight="700" fill="#0C0C0E" text-anchor="middle">' + s + '</text>'
    + '<text x="' + cx + '" y="' + (cy + 12) + '" font-family="Inter,sans-serif" font-size="10" fill="#BBBBC2" text-anchor="middle">/25</text>'
    + '<text x="' + cx + '" y="104" font-family="Inter,sans-serif" font-size="9" font-weight="700" fill="#67676E" text-anchor="middle" letter-spacing="0.12em">' + label.toUpperCase() + '</text>'
    + '</svg>';
}

// ── PERSONALISED LETTER ───────────────────────────────────────────────────────
function buildLetter(bizName, score, trustScore, compName, input) {
  var tier = score >= 76 ? 'Chosen' : score >= 56 ? 'Considered' : score >= 31 ? 'Seen' : 'Not seen';
  var gapDesc = score >= 76
    ? 'Your position is strong. This report shows how to make it unassailable.'
    : score >= 56
    ? 'You are being considered but not consistently chosen. The gap is specific and fixable.'
    : score >= 31
    ? 'AI platforms can find you, but they are not selecting you. The structural gap is significant but closeable.'
    : 'AI platforms are not selecting you in your category. The gap is wide, but it is fully addressable.';
  var trustNote = trustScore <= 8
    ? 'Your Trust score is ' + trustScore + ' out of 25. That is the primary driver of your current position — and the first thing to fix. Every other pillar improves once Trust moves.'
    : trustScore <= 15
    ? 'Your Trust score of ' + trustScore + ' out of 25 is the biggest gap. Closing it will move your overall score significantly within 30 days.'
    : 'Your Trust score of ' + trustScore + ' out of 25 is solid. The improvements needed are more nuanced — see the pillar breakdown for specifics.';
  var compNote = compName
    ? 'When AI is asked for your category, it is recommending ' + esc(compName) + ' instead. This report explains exactly why — and exactly what to do to reverse it.'
    : 'This report identifies the specific signals preventing your selection — and gives you the exact actions to close them.';
  var projScore = Math.min(95, score + 14);
  return '<div class="letter">'
    + '<div class="letter-eyebrow">Personal note from the founder</div>'
    + '<div class="letter-salutation">Dear ' + esc(bizName) + ',</div>'
    + '<p class="letter-p">I want to be direct with you about what we found.</p>'
    + '<p class="letter-p">Your score is <strong>' + score + ' out of 100</strong>. That places you in the <em>' + tier + '</em> tier. ' + gapDesc + '</p>'
    + '<p class="letter-p">' + trustNote + '</p>'
    + '<p class="letter-p">' + compNote + '</p>'
    + '<p class="letter-p">This report tells you exactly where the gap is, exactly what AI said when your customers asked for your category, and exactly what to do in the next 30 days. The actions are sequenced by impact. The assets are ready to use. Everything in this report is specific to <strong>' + esc(bizName) + '</strong> — not generic advice.</p>'
    + '<p class="letter-p">Run the free diagnostic again after 30 days. Based on what we found, I expect your score to reach <strong>' + projScore + '</strong> or above if you implement what is in front of you. That is not optimism — it is what the evidence says is achievable.</p>'
    + '<div class="letter-sign">'
    + '<div class="letter-name">Blessing Ashionye Ebogu</div>'
    + '<div class="letter-title">Founder &amp; CEO</div>'
    + '<div class="letter-brand">CHOIVE·</div>'
    + '</div>'
    + '</div>';
}

